// effectiveStatus collapses the pool's in-memory lifecycle and the
// session's on-disk Status into one label the UI dot/badge can render.
// Lifecycle wins when present (it's the live view); falls back to
// Status="queued" so sessions waiting for a slot still show a colour
// instead of going invisible. Empty result = no dot.
func effectiveStatus(lifecycle, status string) string {
	if lifecycle != "" && lifecycle != "killed" {
		return lifecycle
	}
	if status == "queued" {
		return "queued"
	}
	return ""
}

